import anthropic
import json

client = anthropic.Anthropic()


def call(messages: list[dict], max_tokens: int = 400) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        messages=messages,
    ).content[0].text.strip()


def parse_with_retry(prompt: str, max_retries: int = 3) -> dict | list:
    messages = [{"role": "user", "content": prompt}]

    for attempt in range(1, max_retries + 1):
        raw = call(messages)
        try:
            return parse_json_robust(raw)  # extract + sanitise + parse
        except (ValueError, json.JSONDecodeError) as e:
            if attempt == max_retries:
                raise
            messages.append({"role": "assistant", "content": raw})
            messages.append({
                "role": "user",
                "content": (
                    f"Parse error: {e}\n"
                    "Please output ONLY valid JSON — no preamble, no markdown fences, "
                    "no trailing commas. Use double quotes for all strings."
                ),
            })

    raise ValueError("Unreachable")


result = parse_with_retry(
    "Extract the key facts from this sentence as a JSON object with fields "
    "'who', 'did_what', 'when', and 'where'.\n\n"
    "On 14 March 2024, Apple CEO Tim Cook announced a new AI initiative in San Francisco."
)
print(json.dumps(result, indent=2))
